const posts = $input.all();
const scored = [];

for (const post of posts) {
  const p = post.json;
  if (p.error || !p.id) continue;

  const likes = p.likesCount || 0;
  const comments = p.commentsCount || 0;
  const views = p.videoViewCount || p.videoPlayCount || null;
  const followers = p.ownerFollowersCount || 1;

  // Engagement score: comments weighted 5x — intent signal stronger than passive like
  const rawScore = (comments * 5) + likes;
  const engagementScore = parseFloat((rawScore / followers * 100).toFixed(4));

  const caption = (p.caption || '').trim();
  const lines = caption.split('\n').filter(l => l.trim().length > 0);
  const firstLine = lines[0] || '';
  const hookText = firstLine.length >= 15 ? firstLine : (caption.split('.')[0] || firstLine);

  if (!hookText || hookText.length < 5) continue;

  // Extract hashtags from caption
  const hashtags = (caption.match(/#[\w\u00C0-\u017F]+/g) || []).map(h => h.toLowerCase());

  let format = 'feed';
  if (p.type === 'Video') format = 'reel';
  else if (p.type === 'Sidecar') format = 'carousel';

  scored.push({
    json: {
      post_id: String(p.id || p.shortCode || ''),
      post_url: p.url || ('https://www.instagram.com/p/' + (p.shortCode || '')),
      source_account: p.ownerUsername || 'unknown',
      format: format,
      caption_as_script: caption.substring(0, 3000),
      hook_text: hookText.substring(0, 500),
      hashtags: hashtags,
      likes: likes,
      comments: comments,
      views: views,
      engagement_score: engagementScore,
      posted_at: p.timestamp || null
    }
  });
}

// Sort by engagement score, return top 3
scored.sort((a, b) => b.json.engagement_score - a.json.engagement_score);
return scored.slice(0, 3);

// FIX: Build Claude payload in a Code node to safely escape all special characters
// This prevents JSON malformation when captions contain quotes, newlines, or emojis

const post = $input.first().json;

const systemContext = `You are FREYJA, content intelligence analyst for Runa Systems — a high-ticket AI consulting brand (R$15k-50k/year) that sells AI agent orchestration, Claude Code, n8n automation, and business transformation to Brazilian entrepreneurs. Your job is to extract deep content intelligence from competitor/reference Instagram posts so FREYJA can create superior content for @arthsystems_.`;

const userPrompt = `Analyze this Instagram post and return ONLY a valid JSON object. No markdown. No explanation.

ACCOUNT: ${post.source_account}
FORMAT: ${post.format}
ENGAGEMENT: ${post.likes} likes | ${post.comments} comments${post.views ? ' | ' + post.views + ' views' : ''}
SCORE: ${post.engagement_score}
HASHTAGS: ${(post.hashtags || []).join(' ')}

CAPTION / SCRIPT:
${post.caption_as_script}

Return this exact JSON:
{
  "hook_type": "<question|attack|contradiction|reveal|mirror|social_proof|manifesto|curiosity_gap>",
  "hook_text_refined": "<clean version of the opening hook, max 120 chars>",
  "content_topic": "<main subject in 3-5 words>",
  "keywords": ["<keyword1>", "<keyword2>", "<keyword3>"],
  "key_phrases": ["<power phrase 1>", "<power phrase 2>", "<power phrase 3>"],
  "narrative_structure": {
    "hook": "<first attention-grabbing element>",
    "conflict": "<problem or tension presented>",
    "resolution": "<solution or insight offered>",
    "cta": "<call to action text or empty string>"
  },
  "trigger_emotions": ["<medo|aspiracao|urgencia|FOMO|identidade|inveja|curiosidade|orgulho|raiva|alegria>"],
  "solutions_presented": "<what specific solution or value the post delivers>",
  "transformation_promised": "<before state> → <after state implied by the content>",
  "objections_handled": ["<objection 1 that the content pre-handles>"],
  "cta_type": "<dm|link|save|comment|share|follow|none>",
  "cta_text": "<exact CTA text from the caption or empty string>",
  "buy_trigger": "<urgency|aspiration|fear|social_proof|identity|curiosity>",
  "content_pillars": ["<education|inspiration|entertainment|promotion|community>"],
  "applicable_formats": ["<carousel|reel|caption>"],
  "replicable_structure": "<step-by-step formula to replicate this content format for @arthsystems_>",
  "runa_product_fit": "<RUNA_SYSTEMS|QUAD|CREATOR|AGENT|SITE|POSICIONAMENTO|MIND|NONE — which product/module this content maps to>",
  "why_it_worked": "<2-3 sentences explaining the specific engagement drivers>",
  "relevance_score": <0.0 to 1.0 — how relevant to: AI agents, Claude Code, automation, cloud infra, high-ticket business scaling for PT-BR audience>
}`;

return [{
  json: {
    ...post,
    claude_payload: {
      model: 'claude-haiku-4-5-20251001',
      max_tokens: 1500,
      system: systemContext,
      messages: [{ role: 'user', content: userPrompt }]
    }
  }
}];

// FIX: Process ALL items — previous version used $input.first() losing 2 of 3 posts
// Use $input.all().map() to classify every item that comes through

return $input.all().map(item => {
  const claudeResponse = item.json;
  const postData = $('Score & Filter Posts').item.json;

  let analysis = {};
  try {
    const text = claudeResponse.content && claudeResponse.content[0] && claudeResponse.content[0].text
      ? claudeResponse.content[0].text.trim()
      : '{}';
    // Strip markdown code fences if Claude wraps in ```json
    const cleaned = text.replace(/^```(?:json)?\n?|```$/gm, '').trim();
    analysis = JSON.parse(cleaned);
  } catch(e) {
    analysis = {
      hook_type: 'curiosity_gap',
      hook_text_refined: postData.hook_text ? postData.hook_text.substring(0, 120) : '',
      content_topic: 'parse_error',
      keywords: [],
      key_phrases: [],
      narrative_structure: { hook: '', conflict: '', resolution: '', cta: '' },
      trigger_emotions: [],
      solutions_presented: '',
      transformation_promised: '',
      objections_handled: [],
      cta_type: 'none',
      cta_text: '',
      buy_trigger: 'curiosity',
      content_pillars: [],
      applicable_formats: [],
      replicable_structure: '',
      runa_product_fit: 'NONE',
      why_it_worked: 'Claude parse error: ' + e.message,
      relevance_score: 0
    };
  }

  return { json: { ...postData, ...analysis } };
});
